import React, { useState, useRef } from 'react';
import Button from '~/components/Button';
import SortBox from '~/components/SortBox';
const QuickSort = () => {
    console.log('123');
    const refArray = useRef(getRandomNoDuplicateArray(99));
    const [tempArray, setTempArray] = useState(refArray.current);
    const onStart = async () => {
        await quickSort(refArray.current);
    };
    const quickSort = async (array, length = array.length - 1, start = 0) => {
        if (array.length < 2)
            return array; // base case
        let left = [];
        let right = [];
        let pivot = array[length];
        while (start < length) {
            if (array[start] < pivot) {
                left.push(array[start]);
            }
            else {
                right.push(array[start]);
            }
            start++;
        }
        refArray.current = replaceOrignalPartArray(refArray.current, pivot, [
            ...left,
            pivot,
            ...right,
        ]);
        setTempArray(refArray.current);
        await sleep(100);
        return [...(await quickSort(left)), pivot, ...(await quickSort(right))];
    };
    const replaceOrignalPartArray = (orgArray, pivot, changeArray) => {
        const temp = new Array(...orgArray);
        temp.splice(temp.findIndex((i) => i === pivot) - (changeArray.length - 1), changeArray.length, ...changeArray);
        return temp;
    };
    return (React.createElement("div", { className: "flex flex-row" },
        React.createElement("span", { className: " flex flex-col font-bold text-lg text-white" },
            React.createElement("span", null, "QickSort"),
            React.createElement("span", null,
                "count:",
                tempArray.length)),
        React.createElement("div", { className: "w-full flex items-end mr-2 mb-2" },
            React.createElement(Button, { onClick: onStart }, " start")),
        React.createElement("div", { className: "flex w-full flex-row items-end max-h-[94vh]" }, tempArray.map((item, index) => (React.createElement(SortBox, { key: index, height: item, width: 2 }))))));
};
export default QuickSort;
async function sleep(ms) {
    return new Promise((r) => setTimeout(r, ms));
}
function getRandomNoDuplicateArray(maxValue) {
    let result = [];
    while (result.length < maxValue) {
        const randomValu = Math.floor(Math.random() * maxValue) + 1;
        if (result.indexOf(randomValu) === -1)
            result.push(randomValu);
    }
    return result;
}
